void ZopfliCleanHash(ZopfliHash *h)
{
    free(h->head);
    free(h->prev);
    free(h->hashval);

    free(h->head2);
    free(h->prev2);
    free(h->hashval2);

    free(h->same);
}

void ZopfliAllocHash(size_t window_size, ZopfliHash *h)
__CPROVER_requires(window_size > 0)
__CPROVER_requires(window_size <= __CPROVER_max_malloc_size / sizeof(int))
__CPROVER_requires(__CPROVER_is_fresh(h, sizeof(*h)))
__CPROVER_assigns(__CPROVER_object_whole(h))
__CPROVER_ensures(__CPROVER_is_fresh(h->head, sizeof(int) * 65536))
__CPROVER_ensures(__CPROVER_is_fresh(h->prev, sizeof(unsigned short) * window_size))
__CPROVER_ensures(__CPROVER_is_fresh(h->hashval, sizeof(int) * window_size))
__CPROVER_ensures(__CPROVER_is_fresh(h->same, sizeof(unsigned short) * window_size))
__CPROVER_ensures(__CPROVER_is_fresh(h->head2, sizeof(int) * 65536))
__CPROVER_ensures(__CPROVER_is_fresh(h->prev2, sizeof(unsigned short) * window_size))
__CPROVER_ensures(__CPROVER_is_fresh(h->hashval2, sizeof(int) * window_size))
{
    h->head = (int *)malloc(sizeof(*h->head) * 65536);
    h->prev = (unsigned short *)malloc(sizeof(*h->prev) * window_size);
    h->hashval = (int *)malloc(sizeof(*h->hashval) * window_size);

    h->same = (unsigned short *)malloc(sizeof(*h->same) * window_size);

    h->head2 = (int *)malloc(sizeof(*h->head2) * 65536);
    h->prev2 = (unsigned short *)malloc(sizeof(*h->prev2) * window_size);
    h->hashval2 = (int *)malloc(sizeof(*h->hashval2) * window_size);

